import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize]; // Fixed size buffer

        // Copy user input into the buffer with proper bounds checking
        int lengthToCopy = Math.min(userInput.length(), bufferSize); // Limit input length to buffer size
        userInput.getChars(0, lengthToCopy, buffer, 0);

        // Display or process the sanitized input
        System.out.println("Sanitized input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
